module ripple_carry_adder(
    input [3:0] a,
    input [3:0] b,
    input cin,
    output [3:0] sum,
    output cout
);
    wire [3:0] obf_c;
    assign {obf_c[0], sum[0]} = a[0] + b[0] + cin;
    assign {obf_c[1], sum[1]} = a[1] + b[1] + obf_c[0];
    assign {obf_c[2], sum[2]} = a[2] + b[2] + obf_c[1];
    assign {obf_c[3], sum[3]} = a[3] + b[3] + obf_c[2];
    assign cout = obf_c[3];
endmodule
